def test_ping_host_command_injection():
    """Test command injection prevention."""
    payloads = ["localhost; cat /etc/passwd", "localhost | whoami", "$(id)"]
    for payload in payloads:
        try:
            result = ping_host(payload)
            if isinstance(result, (str, bytes)):
                result_str = result.decode() if isinstance(result, bytes) else result
                assert "root:" not in result_str, "Command injection: passwd leaked"
                assert "uid=" not in result_str, "Command injection: id executed"
        except (ValueError, OSError):
            pass  # Rejecting is secure

